import{_ as e,o as d,c as r,a2 as a}from"./chunks/framework.BZO4qERu.js";const b=JSON.parse('{"title":"騎砍2 | 夥伴全指南：你的第二把劍","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/companions.md","filePath":"bannerlord/companions.md"}'),n={name:"bannerlord/companions.md"};function o(l,t,h,i,s,g){return d(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="騎砍2-夥伴全指南-你的第二把劍" tabindex="-1">騎砍2 | 夥伴全指南：你的第二把劍 <a class="header-anchor" href="#騎砍2-夥伴全指南-你的第二把劍" aria-label="Permalink to &quot;騎砍2 | 夥伴全指南：你的第二把劍&quot;">​</a></h1><blockquote><p>適用版本：v1.4.x（2026年6月最新）</p></blockquote><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>夥伴不是背包工具人。一個好的夥伴可以幫你帶兵、管城、跑商隊、打競技場、甚至當領主。但每個版本夥伴的技能和出現區域都有差異，這篇以 v1.4.x 現行版本為準。</p><hr><h2 id="一、夥伴去哪找" tabindex="-1">一、夥伴去哪找 <a class="header-anchor" href="#一、夥伴去哪找" aria-label="Permalink to &quot;一、夥伴去哪找&quot;">​</a></h2><h3 id="_1-1-百科全書查詢" tabindex="-1">1.1 百科全書查詢 <a class="header-anchor" href="#_1-1-百科全書查詢" aria-label="Permalink to &quot;1.1 百科全書查詢&quot;">​</a></h3><p>打開百科全書（N鍵）→ 英雄 → 篩選「Wanderer 流浪者」→ 會列出全大陸目前所有可招募的夥伴跟他們所在城鎮。</p><blockquote><p>💡 夥伴會在地圖上移動，今天在帝國，下週可能在巴坦尼亞。百科全書會即時顯示位置。</p></blockquote><h3 id="_1-2-在酒館招募" tabindex="-1">1.2 在酒館招募 <a class="header-anchor" href="#_1-2-在酒館招募" aria-label="Permalink to &quot;1.2 在酒館招募&quot;">​</a></h3><p>去城鎮 → 酒館區 → 找有名字的流浪者對話 → 付錢招募。</p><hr><h2 id="二、夥伴類型-v1-4-x-現行版本" tabindex="-1">二、夥伴類型（v1.4.x 現行版本） <a class="header-anchor" href="#二、夥伴類型-v1-4-x-現行版本" aria-label="Permalink to &quot;二、夥伴類型（v1.4.x 現行版本）&quot;">​</a></h2><h3 id="🛡️-軍需官-quartermaster-—-管理學" tabindex="-1">🛡️ 軍需官（Quartermaster）— 管理學 <a class="header-anchor" href="#🛡️-軍需官-quartermaster-—-管理學" aria-label="Permalink to &quot;🛡️ 軍需官（Quartermaster）— 管理學&quot;">​</a></h3><table tabindex="0"><thead><tr><th>稱號</th><th>文化/出現區域</th><th>核心技能</th><th style="text-align:center;">評價</th></tr></thead><tbody><tr><td><strong>the Spicevendor</strong></td><td>阿塞萊 Aserai</td><td>交易、管理學</td><td style="text-align:center;">⭐⭐⭐ 最強</td></tr><tr><td><strong>Willowbark</strong></td><td>帝國 Empire</td><td>管理學、醫學</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td><strong>the Wainwright</strong></td><td>瓦蘭迪亞 Vlandia</td><td>管理學、工程學</td><td style="text-align:center;">⭐⭐</td></tr></tbody></table><blockquote><p>軍需官增加帶兵上限。讓夥伴當，你自己不要當。</p></blockquote><h3 id="🏥-外科醫生-surgeon-—-醫學" tabindex="-1">🏥 外科醫生（Surgeon）— 醫學 <a class="header-anchor" href="#🏥-外科醫生-surgeon-—-醫學" aria-label="Permalink to &quot;🏥 外科醫生（Surgeon）— 醫學&quot;">​</a></h3><table tabindex="0"><thead><tr><th>稱號</th><th>文化/出現區域</th><th>核心技能</th><th style="text-align:center;">評價</th></tr></thead><tbody><tr><td><strong>the Surgeon</strong></td><td>隨機（較多在帝國）</td><td>醫學專精</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td><strong>Willowbark</strong></td><td>帝國 Empire</td><td>醫學、管理學</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td><strong>the Healer</strong></td><td>巴坦尼亞 Battania</td><td>醫學、魅力</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td><strong>Bitterdraught</strong></td><td>瓦蘭迪亞 Vlandia</td><td>醫學、交易</td><td style="text-align:center;">⭐⭐</td></tr></tbody></table><blockquote><p>外科醫生直接影響戰鬥後傷兵存活率。前期最該優先招募的夥伴類型。</p></blockquote><h3 id="🔭-斥候-scout-—-偵查" tabindex="-1">🔭 斥候（Scout）— 偵查 <a class="header-anchor" href="#🔭-斥候-scout-—-偵查" aria-label="Permalink to &quot;🔭 斥候（Scout）— 偵查&quot;">​</a></h3><table tabindex="0"><thead><tr><th>稱號</th><th>文化/出現區域</th><th>核心技能</th><th style="text-align:center;">評價</th></tr></thead><tbody><tr><td><strong>of the Wastes</strong></td><td>阿塞萊 Aserai</td><td>偵查 170</td><td style="text-align:center;">⭐⭐⭐ 最強</td></tr><tr><td><strong>the Swift</strong></td><td>庫塞特 Khuzait</td><td>偵查 150</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td><strong>Wanderer</strong></td><td>帝國 Empire</td><td>偵查 150</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td><strong>the Tracker</strong></td><td>瓦蘭迪亞 Vlandia</td><td>偵查 120-150</td><td style="text-align:center;">⭐⭐</td></tr><tr><td><strong>Frostbeard</strong></td><td>斯特吉亞 Sturgia</td><td>偵查 110</td><td style="text-align:center;">⭐⭐</td></tr><tr><td><strong>of the Hills</strong></td><td>瓦蘭迪亞/帝國</td><td>偵查 75-110</td><td style="text-align:center;">⭐</td></tr><tr><td><strong>Blacktooth</strong></td><td>巴坦尼亞 Battania</td><td>偵查 90</td><td style="text-align:center;">⭐</td></tr><tr><td><strong>the Alone</strong></td><td>庫塞特 Khuzait</td><td>偵查 75</td><td style="text-align:center;">⭐</td></tr><tr><td><strong>the Ragged</strong></td><td>巴坦尼亞 Battania</td><td>偵查 70</td><td style="text-align:center;">⭐</td></tr></tbody></table><blockquote><p>斥候增加地圖視野和移動速度。跑得快 = 安全。</p></blockquote><h3 id="🔧-工程師-engineer-—-工程學" tabindex="-1">🔧 工程師（Engineer）— 工程學 <a class="header-anchor" href="#🔧-工程師-engineer-—-工程學" aria-label="Permalink to &quot;🔧 工程師（Engineer）— 工程學&quot;">​</a></h3><table tabindex="0"><thead><tr><th>稱號</th><th>文化/出現區域</th><th>核心技能</th><th style="text-align:center;">評價</th></tr></thead><tbody><tr><td><strong>the Engineer</strong></td><td>隨機</td><td>工程學專精</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td><strong>the Scholar</strong></td><td>帝國 Empire</td><td>醫學、工程學</td><td style="text-align:center;">⭐⭐</td></tr><tr><td><strong>the Wainwright</strong></td><td>瓦蘭迪亞 Vlandia</td><td>管理學、工程學</td><td style="text-align:center;">⭐⭐</td></tr><tr><td><strong>the Knowing</strong></td><td>帝國 Empire</td><td>智力型、多技能</td><td style="text-align:center;">⭐⭐</td></tr><tr><td><strong>the Accursed</strong></td><td>斯特吉亞 Sturgia</td><td>工程學、戰術</td><td style="text-align:center;">⭐</td></tr></tbody></table><blockquote><p>工程學影響圍城速度和建築時間。自立為王後必備。</p></blockquote><h3 id="⚔️-戰士型-—-打架用" tabindex="-1">⚔️ 戰士型 — 打架用 <a class="header-anchor" href="#⚔️-戰士型-—-打架用" aria-label="Permalink to &quot;⚔️ 戰士型 — 打架用&quot;">​</a></h3><table tabindex="0"><thead><tr><th>稱號</th><th>文化/出現區域</th><th>核心技能</th><th style="text-align:center;">評價</th></tr></thead><tbody><tr><td><strong>the Sword</strong> / <strong>Shieldmaiden</strong></td><td>瓦蘭迪亞/斯特吉亞</td><td>單手、長桿</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td><strong>the Bull</strong></td><td>斯特吉亞 Sturgia</td><td>戰術、雙手、長桿</td><td style="text-align:center;">⭐⭐</td></tr><tr><td><strong>the Boar</strong></td><td>巴坦尼亞 Battania</td><td>戰術、長桿</td><td style="text-align:center;">⭐⭐</td></tr><tr><td><strong>the Golden</strong></td><td>帝國 Empire</td><td>戰術高</td><td style="text-align:center;">⭐⭐</td></tr><tr><td><strong>the Black</strong></td><td>瓦蘭迪亞 Vlandia</td><td>流氓習氣、弓</td><td style="text-align:center;">⭐</td></tr></tbody></table><h3 id="🐪-商隊型-—-帶商隊賺錢" tabindex="-1">🐪 商隊型 — 帶商隊賺錢 <a class="header-anchor" href="#🐪-商隊型-—-帶商隊賺錢" aria-label="Permalink to &quot;🐪 商隊型 — 帶商隊賺錢&quot;">​</a></h3><table tabindex="0"><thead><tr><th>稱號</th><th>文化/出現區域</th><th>核心技能</th><th style="text-align:center;">評價</th></tr></thead><tbody><tr><td><strong>the Spicevendor</strong></td><td>阿塞萊 Aserai</td><td>交易、管理學</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td><strong>the Swift</strong></td><td>庫塞特 Khuzait</td><td>交易、偵查</td><td style="text-align:center;">⭐⭐</td></tr></tbody></table><blockquote><p>交易技能越高，商隊日收入越高。商隊成本 15000 金。</p></blockquote><hr><h2 id="三、夥伴職位設定" tabindex="-1">三、夥伴職位設定 <a class="header-anchor" href="#三、夥伴職位設定" aria-label="Permalink to &quot;三、夥伴職位設定&quot;">​</a></h2><p>打開家族介面 → 夥伴 → 分配職位：</p><table tabindex="0"><thead><tr><th>職位</th><th>需要的技能</th><th>效果</th></tr></thead><tbody><tr><td>軍需官</td><td>管理學</td><td>增加帶兵上限</td></tr><tr><td>斥候</td><td>偵查</td><td>地圖視野擴大、移動加速</td></tr><tr><td>外科醫生</td><td>醫學</td><td>傷兵恢復率提高</td></tr><tr><td>工程師</td><td>工程學</td><td>圍城速度加快</td></tr></tbody></table><hr><h2 id="四、招募費用" tabindex="-1">四、招募費用 <a class="header-anchor" href="#四、招募費用" aria-label="Permalink to &quot;四、招募費用&quot;">​</a></h2><ul><li>初期流浪者：500-2000 金</li><li>中期有技能的：2000-5000 金</li><li>高技能稀有型（如 of the Wastes、the Spicevendor）：可能更貴</li></ul><hr><h2 id="五、各文化區域快速找夥伴" tabindex="-1">五、各文化區域快速找夥伴 <a class="header-anchor" href="#五、各文化區域快速找夥伴" aria-label="Permalink to &quot;五、各文化區域快速找夥伴&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文化區域</th><th>主要城鎮</th><th>容易找到的夥伴</th></tr></thead><tbody><tr><td>帝國</td><td>Argoron、Danustica、Saneopa</td><td>Willowbark、the Scholar、the Golden、Wanderer</td></tr><tr><td>巴坦尼亞</td><td>Marunath、Seonon、Dunglanys</td><td>the Healer、the Boar、Blacktooth、the Ragged</td></tr><tr><td>瓦蘭迪亞</td><td>Pravend、Ocs Hall、Jaculan</td><td>the Tracker、the Wainwright、Bitterdraught</td></tr><tr><td>斯特吉亞</td><td>Omor、Balgard、Revyl</td><td>Frostbeard、the Bull、the Accursed</td></tr><tr><td>庫塞特</td><td>Makeb、Odokh、Chaikand</td><td>the Swift、the Alone</td></tr><tr><td>阿塞萊</td><td>Husn Fulq、Razih、Qasira</td><td>of the Wastes、the Spicevendor</td></tr></tbody></table><hr><h2 id="六、推薦早期招募優先級" tabindex="-1">六、推薦早期招募優先級 <a class="header-anchor" href="#六、推薦早期招募優先級" aria-label="Permalink to &quot;六、推薦早期招募優先級&quot;">​</a></h2><ol><li><strong>外科醫生</strong>（任何有醫學技能的）— 降低傷亡率，最重要</li><li><strong>斥候</strong>（偵查高）— 地圖跑得快，安全</li><li><strong>軍需官</strong>（管理學）— 增加帶兵上限</li><li><strong>工程師</strong>（攻城用，不急）</li></ol><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./kingdom-management.html">騎砍2 | 王國管理深度指南</a></li><li><a href="./clan-family.html">騎砍2 | 家族與結婚系統</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫，含各夥伴文化區域分布。</li></ul>',52)])])}const u=e(n,[["render",o]]);export{b as __pageData,u as default};
